import anthropic
import openai
import json
from dataclasses import dataclass

anthropic_client = anthropic.Anthropic()
openai_client = openai.OpenAI()


@dataclass
class EvalCase:
    input: str
    expected_contains: list[str]  # substrings that must appear in a correct answer
    must_not_contain: list[str] = None


EVAL_SET = [
    EvalCase(
        input="Explain the difference between a mutex and a semaphore.",
        expected_contains=["mutual exclusion", "binary", "counting"],
    ),
    EvalCase(
        input="What does 'immutable' mean in functional programming?",
        expected_contains=["cannot be changed", "new"],
    ),
    EvalCase(
        input="When should you use async/await vs threading in Python?",
        expected_contains=["I/O", "GIL"],
    ),
]


def call_anthropic(prompt: str, model: str) -> str:
    resp = anthropic_client.messages.create(
        model=model,
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    return resp.content[0].text


def call_openai(prompt: str, model: str) -> str:
    resp = openai_client.chat.completions.create(
        model=model,
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    return resp.choices[0].message.content


def score_response(response: str, case: EvalCase) -> float:
    """Returns fraction of expected_contains substrings found."""
    hits = sum(
        1 for phrase in case.expected_contains
        if phrase.lower() in response.lower()
    )
    return hits / len(case.expected_contains)


def run_eval(call_fn, model: str) -> float:
    scores = []
    for case in EVAL_SET:
        response = call_fn(case.input, model)
        scores.append(score_response(response, case))
    return sum(scores) / len(scores)


# Compare models on the task
models = [
    (call_anthropic, "claude-haiku-4-5-20251001"),
    (call_anthropic, "claude-sonnet-4-6"),
    (call_openai,    "gpt-4o-mini"),
]
for fn, model in models:
    score = run_eval(fn, model)
    print(f"{model}: {score:.2%}")
